        tc_resync_br_d = tc_resync_br_q;

        if (reported_update) begin
            tc_reported_d = reported_status;
        end

        if (tc_resync_br) begin
            tc_resync_br_d = '1;
        end

        if (valid_o && 
            (packet_format_o == te_pkg::F_DIFF_DELTA || 
            packet_format_o == te_pkg::F_ADDR_ONLY)) begin
            tc_resync_br_d = '0;
